import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { ref, get, child } from "firebase/database";

const StudentDashboard = ({ user }) => {
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      const dbRef = ref(db);
      const userKey = user.email.replace(/\./g, ',');
      try {
        const snapshot = await get(child(dbRef, `students/${userKey}`));
        if (snapshot.exists()) {
          setUserData(snapshot.val());
        } else {
          // Default data for shared BSL account or new students
          setUserData({
            name: user.name,
            progress: 0,
            averageScore: 0,
            attendance: { present: 0, absent: 0, leave: 0 },
            assignments: { submitted: 0, total: 0 }
          });
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [user.email, user.name]);

  if (loading) {
    return <div>Loading your dashboard...</div>;
  }

  // Ensure nested objects exist to prevent crashes
  const attendance = userData?.attendance || { present: 0, absent: 0, leave: 0 };
  const assignments = userData?.assignments || { submitted: 0, total: 0 };
  
  const totalClasses = (attendance.present || 0) + (attendance.absent || 0) + (attendance.leave || 0);
  const attendanceRate = totalClasses > 0 ? Math.round((attendance.present / totalClasses) * 100) : 0;

  return (
    <div className="container">
      <h1>Student Dashboard</h1>
      <p>Welcome back, {user.name}!</p>
      
      <div className="dashboard-grid">
        <div className="dashboard-card">
          <h3>{userData.progress}%</h3>
          <p>Overall Progress</p>
        </div>
        
        <div className="dashboard-card">
          <h3>{userData.attendance.present}/30</h3>
          <p>Classes Attended</p>
        </div>
        
        <div className="dashboard-card">
          <h3>{userData.assignments.submitted}/{userData.assignments.total}</h3>
          <p>Assignments Submitted</p>
        </div>
        
        <div className="dashboard-card">
          <h3>{userData.averageScore}%</h3>
          <p>Average Score</p>
        </div>
      </div>

      <div className="card">
        <h3>Attendance Summary</h3>
        <div className="dashboard-grid">
          <div className="dashboard-card">
            <h3>{userData.attendance.present}</h3>
            <p>Present</p>
          </div>
          <div className="dashboard-card">
            <h3>{userData.attendance.absent}</h3>
            <p>Absent</p>
          </div>
          <div className="dashboard-card">
            <h3>{userData.attendance.leave}</h3>
            <p>Leave</p>
          </div>
          <div className="dashboard-card">
            <h3>{attendanceRate}%</h3>
            <p>Attendance Rate</p>
          </div>
        </div>
      </div>

      <div className="card">
        <h3>Exam Schedule</h3>
        <div style={{ textAlign: 'left' }}>
          {(() => {
            const savedSchedule = JSON.parse(localStorage.getItem('examSchedule')) || { slots: [] };
            const slots = savedSchedule.slots || [];
            
            if (slots.length === 0) {
              return <p>No exams currently scheduled.</p>;
            }

            return (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                {slots.map((slot, index) => {
                  const now = new Date();
                  const start = new Date(slot.start);
                  const end = new Date(slot.end);
                  const isActive = now >= start && now <= end;
                  const isUpcoming = now < start;

                  return (
                    <div key={index} style={{ 
                      padding: '15px', 
                      borderRadius: '8px', 
                      borderLeft: `5px solid ${isActive ? '#4CAF50' : isUpcoming ? '#2196F3' : '#9e9e9e'}`,
                      background: '#f9f9f9',
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center'
                    }}>
                      <div>
                        <strong style={{ fontSize: '1.1rem' }}>{(slot.course || 'General').replace('_', ' ').toUpperCase()}</strong>
                        <div style={{ fontSize: '0.9rem', color: '#666' }}>
                          Start: {start.toLocaleString()} | End: {end.toLocaleString()}
                        </div>
                        {isActive && <span style={{ color: '#4CAF50', fontWeight: 'bold', fontSize: '0.8rem' }}>● ACTIVE NOW</span>}
                        {isUpcoming && <span style={{ color: '#2196F3', fontWeight: 'bold', fontSize: '0.8rem' }}>UPCOMING</span>}
                      </div>
                      {isActive && <a href="/exam" className="btn btn-small btn-success">Join Exam</a>}
                    </div>
                  );
                })}
              </div>
            );
          })()}
        </div>
      </div>

      <div className="card">
        <h3>Quick Actions</h3>
        <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap' }}>
          <a href="/exam" className="btn btn-primary">Take Exam</a>
          <a href="/result" className="btn btn-success">Download Last Result</a>
          <a href="/project-upload" className="btn">Upload Project</a>
        </div>
      </div>
    </div>
  );
};

export default StudentDashboard;
